"""Part 3: Accompaniments(30) + Desserts(25) = 55 recipes, SL_0286-SL_0340"""
import json
def m(i,n,c,d,p,ck,s,r,sp,ings,mt,t,cn):
    return {"id":f"SL_{i:04d}","names":{"english":n},"category":c,"difficulty":d,"prep_time_mins":p,"cook_time_mins":ck,"servings":s,"region":r,"spice_level":sp,"is_authentic":True,"ingredients":[{"name":x,"amount":y} for x,y in ings],"method":mt,"tips":t,"cultural_note":cn}
R=[]
# ACCOMPANIMENTS (30) SL_0286-0315
R.append(m(286,"Pol Sambol (Coconut Sambol)","accompaniment","easy",10,0,4,"Island-wide",3,[("grated coconut","1 cup"),("red onion","1"),("dried chili flakes","2 tbsp"),("Maldive fish","1 tbsp"),("lime juice","2 tbsp"),("salt","to taste")],"1. Grate fresh coconut\n2. Finely chop red onion\n3. Mix coconut, onion, chili flakes, Maldive fish\n4. Add lime juice and salt\n5. Mix well, crushing slightly with fingers\n6. Serve immediately","Use freshly grated coconut, never desiccated, for authentic sambol.","Pol sambol is the king of Sri Lankan sambols, present at every single meal."))
R.append(m(287,"Seeni Sambol (Caramelized Onion Sambol)","accompaniment","medium",15,30,6,"Western Province",2,[("red onion","500g"),("chili flakes","2 tbsp"),("Maldive fish","2 tbsp"),("sugar","1 tbsp"),("tamarind paste","1 tbsp"),("curry leaves","2 sprigs"),("cinnamon stick","1"),("cardamom","3 pods"),("oil","1/4 cup"),("salt","to taste")],"1. Slice onions thinly\n2. Heat oil, add cinnamon, cardamom\n3. Add onions, cook on low heat 20 mins until deep brown\n4. Add chili flakes, Maldive fish\n5. Add tamarind, sugar, curry leaves\n6. Cook 10 more mins until sticky and caramelized","Patience is key - rush the caramelizing and it won't taste right.","Seeni sambol means 'sugar sambol'. This sweet-spicy onion relish is the classic accompaniment to bread and hoppers."))
R.append(m(288,"Lunu Miris (Chili Paste)","accompaniment","easy",5,0,4,"Island-wide",4,[("dried red chili","8"),("red onion","1"),("Maldive fish","2 tbsp"),("lime juice","2 tbsp"),("salt","to taste")],"1. Remove stems from dried chilies\n2. Roughly chop onion\n3. Grind chilies, onion, Maldive fish and salt in mortar and pestle\n4. Pound until well combined but still chunky\n5. Add lime juice, mix well\n6. Serve with kiribath or hoppers","Use a stone mortar and pestle - the texture is better than a blender.","Lunu miris is the fiery chili paste that accompanies kiribath on every auspicious day in Sri Lanka."))
R.append(m(289,"Katta Sambol (Raw Chili Sambol)","accompaniment","easy",10,0,4,"Southern Province",5,[("red onion","2"),("dried red chili","10"),("Maldive fish","3 tbsp"),("lime juice","3 tbsp"),("salt","to taste"),("pepper","1/2 tsp")],"1. Pound dried chilies in mortar until flaky\n2. Add sliced onions and pound lightly\n3. Add Maldive fish, pound briefly\n4. Season with lime juice, salt, pepper\n5. Mix well\n6. Serve as fiery condiment","Pound gently - katta sambol should be chunky, not a paste.","Katta sambol is the hottest of Sri Lankan sambols, a test of spice tolerance!"))
R.append(m(290,"Gotukola Sambol (Pennywort Salad)","accompaniment","easy",15,0,4,"Island-wide",1,[("gotukola leaves","2 cups"),("red onion","1 small"),("green chili","2"),("grated coconut","3 tbsp"),("Maldive fish","1 tbsp"),("lime juice","2 tbsp"),("salt","to taste")],"1. Wash gotukola leaves thoroughly\n2. Finely chop leaves, onion, green chili\n3. Mix with grated coconut and Maldive fish\n4. Add lime juice and salt\n5. Toss well\n6. Serve fresh as a raw salad","Chop the leaves as finely as possible for best texture.","Gotukola salad is Sri Lanka's most nutritious accompaniment, rich in iron and antioxidants."))
R.append(m(291,"Coconut Chutney","accompaniment","easy",10,5,4,"Northern Province",1,[("grated coconut","1 cup"),("green chili","3"),("ginger","1/2 inch"),("curry leaves","1 sprig"),("mustard seeds","1/2 tsp"),("urad dhal","1 tsp"),("oil","1 tbsp"),("salt","to taste")],"1. Blend coconut, green chili, ginger, salt with little water\n2. Heat oil, add mustard seeds and urad dhal\n3. Add curry leaves when seeds pop\n4. Pour tempering over coconut mixture\n5. Mix well\n6. Serve with dosa, idli, or string hoppers","Keep the chutney slightly coarse for texture.","Coconut chutney is the quintessential Tamil accompaniment served with every South Indian breakfast."))
R.append(m(292,"Tomato Chutney","accompaniment","easy",10,15,4,"Northern Province",2,[("tomato","4 large"),("onion","1"),("dried red chili","4"),("garlic","3 cloves"),("mustard seeds","1/2 tsp"),("urad dhal","1 tsp"),("oil","2 tbsp"),("sugar","1 tsp"),("salt","to taste")],"1. Heat oil, add mustard seeds, urad dhal\n2. Saute onions, garlic until soft\n3. Add chopped tomatoes and dried chilies\n4. Cook 10 mins until tomatoes break down\n5. Add sugar, salt, mash lightly\n6. Cool and serve","Ripe, red tomatoes give the best color and flavor.","Tomato chutney is a tangy accompaniment popular in Tamil households across Northern Sri Lanka."))
R.append(m(293,"Murunga Mallum (Moringa Leaf Stir-fry)","accompaniment","easy",15,10,4,"Island-wide",1,[("moringa leaves","3 cups"),("onion","1 small"),("desiccated coconut","3 tbsp"),("green chili","2"),("Maldive fish","1 tbsp"),("turmeric","1/4 tsp"),("salt","to taste"),("lime juice","1 tbsp")],"1. Strip moringa leaves from stems, wash well\n2. Finely chop onion and green chili\n3. Mix all ingredients together\n4. Stir-fry in a dry pan for 5-7 minutes\n5. Add coconut and Maldive fish\n6. Season with lime juice and salt","Pick only fresh, bright green moringa leaves.","Moringa mallum is a powerhouse of nutrition. Sri Lankan grandmothers call it 'nature's multivitamin'."))
R.append(m(294,"Kankun Mallum (Water Spinach Stir-fry)","accompaniment","easy",10,10,4,"Island-wide",1,[("kangkung (water spinach)","2 bunches"),("onion","1 small"),("desiccated coconut","3 tbsp"),("green chili","2"),("Maldive fish","1 tbsp"),("turmeric","1/4 tsp"),("salt","to taste"),("lime juice","1 tbsp")],"1. Wash kangkung, cut into 1-inch pieces\n2. Finely chop onion and green chili\n3. Heat a dry pan, add kangkung\n4. Add onion, chili, turmeric, Maldive fish\n5. Stir-fry until wilted, 5-7 minutes\n6. Add coconut, lime juice, salt","Do not overcook - kangkung should still be bright green.","Kangkung grows wild near water bodies across Sri Lanka and is one of the most affordable green vegetables."))
R.append(m(295,"Wambatu Moju (Eggplant Pickle)","accompaniment","easy",15,20,4,"Western Province",3,[("eggplant","500g"),("onion","2"),("green chili","4"),("mustard seeds","1 tsp"),("vinegar","3 tbsp"),("sugar","2 tbsp"),("chili powder","1 tsp"),("turmeric","1/4 tsp"),("oil for frying","1 cup")],"1. Cut eggplant into thick strips\n2. Rub with turmeric and salt, deep fry until golden\n3. In same oil, fry onion slices and green chilies\n4. Add mustard seeds, chili powder\n5. Add vinegar and sugar, cook 2 mins\n6. Fold in fried eggplant, coat well","Fry eggplant until well browned for the best texture.","Wambatu moju is an essential component of festive meals, especially at Sinhala New Year."))
R.append(m(296,"Lunudehi (Pickled Onions)","accompaniment","easy",10,0,4,"Island-wide",3,[("red onion","6"),("green chili","4"),("vinegar","1/2 cup"),("sugar","2 tbsp"),("salt","1 tsp"),("mustard seeds","1/2 tsp"),("turmeric","1/4 tsp")],"1. Slice onions into rings\n2. Slice green chilies\n3. Mix vinegar, sugar, salt, turmeric\n4. Add onion rings and chilies\n5. Add mustard seeds\n6. Marinate at least 1 hour before serving","Make ahead - the flavor improves with time.","Lunudehi is the Sri Lankan version of pickled onions, always served alongside rice and curry at restaurants."))
R.append(m(297,"Achcharu (Fruit Pickle)","accompaniment","easy",15,0,6,"Island-wide",3,[("green mango","1"),("pineapple","1 cup"),("onion","2"),("green chili","4"),("vinegar","1/4 cup"),("sugar","2 tbsp"),("chili powder","1 tsp"),("mustard paste","1 tsp"),("salt","to taste")],"1. Cut fruits into bite-sized sticks\n2. Slice onions and green chilies\n3. Mix vinegar, sugar, chili powder, mustard paste\n4. Combine all fruits, onions, chilies\n5. Pour dressing over, toss well\n6. Marinate 30 mins before serving","Use firm, unripe fruits for the best crunch.","Achcharu is the beloved Sri Lankan street-side pickle sold by vendors outside schools and temples."))
R.append(m(298,"Dried Chili Sambol","accompaniment","easy",5,5,4,"Southern Province",5,[("dried red chili","15"),("Maldive fish","3 tbsp"),("red onion","2"),("garlic","3 cloves"),("salt","to taste"),("oil","2 tbsp"),("lime juice","1 tbsp")],"1. Dry roast dried chilies briefly\n2. Pound roasted chilies coarsely\n3. Add Maldive fish, pound together\n4. Mix in finely chopped onion and garlic\n5. Heat oil, pour over mixture\n6. Add lime juice and salt","Roasting dried chilies enhances their flavor and reduces raw spice heat.","This intensely hot sambol is for true chili lovers and is popular in the Southern Province."))
R.append(m(299,"Papadam (Papadum)","accompaniment","easy",0,5,4,"Island-wide",1,[("papadam","8"),("oil for frying","1 cup")],"1. Heat oil in a pan\n2. Test with small piece of papadam\n3. Slide papadam into hot oil\n4. Press down with slotted spoon for 3-5 seconds\n5. Flip and fry other side 2-3 seconds\n6. Drain on paper towels, serve crispy","Oil must be very hot for crispy papadam.","Papadam is the ubiquitous crispy wafer served with every rice and curry meal in Sri Lanka."))
R.append(m(300,"Sambar","accompaniment","easy",15,30,4,"Northern Province",2,[("toor dhal","1 cup"),("mixed vegetables","2 cups"),("sambar powder","2 tbsp"),("tamarind paste","1 tbsp"),("onion","1"),("tomato","2"),("mustard seeds","1/2 tsp"),("curry leaves","1 sprig"),("turmeric","1/4 tsp"),("garlic","3 cloves"),("oil","2 tbsp")],"1. Cook toor dhal until soft, mash lightly\n2. Cook vegetables (drumstick, eggplant, carrot) until tender\n3. Add tamarind, sambar powder, turmeric to vegetables\n4. Combine with mashed dhal\n5. Temper with mustard seeds, curry leaves, garlic\n6. Add tempered onions and tomatoes, simmer 10 mins","Use a mix of at least 3 vegetables for best sambar.","Sambar is the essential Tamil side dish, served with rice, dosa, and idli across Northern Sri Lanka."))
R.append(m(301,"Raita (Cucumber Yogurt)","accompaniment","easy",5,0,4,"Island-wide",0,[("yogurt","1 cup"),("cucumber","1"),("onion","1 small"),("green chili","1"),("mint leaves","1 tbsp"),("salt","to taste"),("cumin powder","1/4 tsp")],"1. Grate or fine dice cucumber\n2. Squeeze out excess water\n3. Mix with yogurt\n4. Add finely chopped onion, chili, mint\n5. Season with salt and cumin\n6. Chill before serving","Squeeze excess water from cucumber to keep raita thick.","Raita is a cooling accompaniment that balances spicy curries, common at biriyani meals."))
R.append(m(302,"Malay Pickle","accompaniment","medium",20,15,6,"Western Province",2,[("dates","1 cup"),("raisins","1/2 cup"),("onion","2"),("garlic","6 cloves"),("ginger","2 inch"),("vinegar","1/2 cup"),("sugar","1/4 cup"),("mustard powder","1 tbsp"),("chili powder","1 tsp"),("cinnamon","1/2 tsp"),("oil","3 tbsp")],"1. Chop dates and soak raisins\n2. Heat oil, saute onions, garlic, ginger\n3. Add spices, cook 2 mins\n4. Add dates, raisins, vinegar, sugar\n5. Cook 10 mins until thick and glossy\n6. Cool and store in jar","This pickle gets better with age - make it a day ahead.","Malay pickle is a sweet-spicy condiment reflecting the Malay heritage of Sri Lanka's Colombo Malays."))
R.append(m(303,"Kohila Curry (Lasia Spinosa)","accompaniment","easy",15,25,4,"Sabaragamuwa",1,[("kohila stems","300g"),("grated coconut","3 tbsp"),("onion","1"),("green chili","2"),("turmeric","1/4 tsp"),("Maldive fish","1 tbsp"),("coconut milk","150ml"),("curry leaves","1 sprig")],"1. Peel and slice kohila stems thinly\n2. Boil until tender\n3. Add onion, chili, turmeric, Maldive fish\n4. Add grated coconut and coconut milk\n5. Simmer 10 minutes\n6. Season and serve as accompaniment","Peel the rough outer layer of kohila stems before cooking.","Kohila is a unique Sri Lankan aquatic plant with medicinal properties, used in traditional Ayurvedic treatments."))
R.append(m(304,"Elawalu Hodda (Mixed Vegetable Gravy)","accompaniment","easy",15,25,4,"Island-wide",1,[("mixed vegetables","3 cups"),("onion","1"),("curry powder","1 tbsp"),("turmeric","1/4 tsp"),("coconut milk","300ml"),("curry leaves","1 sprig"),("pandan leaves","1"),("Maldive fish","1 tbsp")],"1. Cut vegetables (carrot, beans, pumpkin, snake gourd) into pieces\n2. Layer in pot with onion, spices, curry leaves\n3. Add thin coconut milk\n4. Cook 15-20 mins until tender\n5. Add thick coconut milk\n6. Simmer 5 mins, season","Use seasonal vegetables and vary combinations.","Elawalu hodda is the everyday mixed vegetable gravy that forms the backbone of the Sri Lankan rice and curry plate."))
R.append(m(305,"Gotu Kola Kanda Sambol","accompaniment","easy",10,0,4,"Central Province",1,[("gotukola","2 cups"),("scraped coconut","3 tbsp"),("red onion","1"),("green chili","2"),("salt","to taste"),("lime juice","1 tbsp"),("pepper","1/4 tsp")],"1. Finely shred gotukola leaves\n2. Dice onion and chili very small\n3. Mix with scraped coconut\n4. Season with salt, pepper, lime\n5. Toss all ingredients together\n6. Serve fresh","Use only fresh leaves, avoid wilted ones.","This raw pennywort sambol is a staple of Central Province meals."))
R.append(m(306,"Leeks and Dhal Sambol","accompaniment","easy",10,15,4,"Island-wide",1,[("leeks","2"),("red lentils","1/2 cup"),("onion","1"),("coconut","2 tbsp"),("Maldive fish","1 tbsp"),("turmeric","1/4 tsp"),("chili flakes","1 tsp"),("oil","1 tbsp")],"1. Slice leeks thinly, wash\n2. Cook lentils until soft\n3. Heat oil, saute onion, leeks\n4. Add cooked dhal, Maldive fish, coconut\n5. Add chili flakes, turmeric\n6. Cook 5 mins, season","Wash leeks thoroughly to remove sand.","Leeks and dhal combination is a nutritious everyday side dish."))
R.append(m(307,"Mint Sambol","accompaniment","easy",10,0,4,"Eastern Province",2,[("fresh mint","2 cups"),("red onion","1"),("green chili","3"),("coconut","2 tbsp"),("lime juice","2 tbsp"),("salt","to taste")],"1. Wash mint leaves, pick from stems\n2. Roughly chop mint, onion, chilies\n3. Grind or chop together\n4. Add coconut\n5. Season with lime juice and salt\n6. Serve fresh","Use only fresh mint leaves for best flavor.","Mint sambol is a refreshing accompaniment especially popular with biriyani meals."))
R.append(m(308,"Fried Bitter Gourd Chips","accompaniment","easy",10,10,4,"Island-wide",2,[("bitter gourd","3"),("turmeric","1/4 tsp"),("chili powder","1/2 tsp"),("salt","to taste"),("rice flour","2 tbsp"),("oil for frying","1 cup")],"1. Slice bitter gourd into thin rounds\n2. Rub with salt, turmeric, leave 10 mins\n3. Squeeze out bitter juice\n4. Dust with rice flour and chili powder\n5. Deep fry until crispy\n6. Drain and serve","Salt and squeeze to remove max bitterness.","Fried bitter gourd chips are a crunchy, addictive side dish."))
R.append(m(309,"Fried Papadums with Toppers","accompaniment","easy",5,5,4,"Island-wide",1,[("papadum","6"),("tomato","1 diced"),("onion","1 diced"),("chili flakes","1 tsp"),("lime juice","1 tbsp")],"1. Fry papadums until crispy\n2. Dice tomato and onion small\n3. Mix veggies with chili flakes and lime\n4. Top each papadum with mixture\n5. Serve immediately\n6. Eat before they go soft","Top just before serving for crispy results.","Topped papadums are a popular party appetizer and snack."))
R.append(m(310,"Kochchi Sambol (Bird's Eye Chili Sambol)","accompaniment","easy",5,0,4,"Southern Province",5,[("bird's eye chili","20"),("red onion","2"),("Maldive fish","2 tbsp"),("lime juice","2 tbsp"),("salt","to taste")],"1. Roughly chop chilies and onion\n2. Pound in mortar with salt\n3. Add Maldive fish, pound lightly\n4. Squeeze lime juice over\n5. Mix well\n6. Serve in small portions","Use gloves when handling bird's eye chilies.","Kochchi sambol is the most ferociously hot sambol in Sri Lanka, using tiny but potent bird's eye chilies."))
R.append(m(311,"Carrot Sambol","accompaniment","easy",10,0,4,"Island-wide",1,[("carrot","3 large"),("onion","1"),("green chili","2"),("lime juice","2 tbsp"),("desiccated coconut","2 tbsp"),("salt","to taste")],"1. Grate carrots\n2. Finely chop onion and chili\n3. Mix all together\n4. Add coconut, lime juice, salt\n5. Toss well\n6. Serve fresh","Use firm, fresh carrots for best crunch.","Carrot sambol adds color and crunch to the plate, and is rich in vitamin A."))
R.append(m(312,"Onion Sambol","accompaniment","easy",5,0,4,"Island-wide",3,[("red onion","3 large"),("chili powder","1 tbsp"),("Maldive fish","1 tbsp"),("lime juice","2 tbsp"),("salt","to taste"),("pepper","1/4 tsp")],"1. Slice onions into thin rings\n2. Separate into individual rings\n3. Mix with chili powder and Maldive fish\n4. Add lime juice, salt, pepper\n5. Toss well\n6. Serve","Let it sit 10 mins for flavors to meld.","A simple but essential sambol served at any quick meal."))
R.append(m(313,"Green Chili Paste (Amu Miris)","accompaniment","easy",5,0,4,"Southern Province",4,[("green chili","10"),("garlic","4 cloves"),("ginger","1 inch"),("vinegar","2 tbsp"),("salt","to taste")],"1. Wash green chilies\n2. Grind chilies, garlic, ginger into paste\n3. Add vinegar and salt\n4. Mix well\n5. Store in clean jar\n6. Use as condiment with anything","Sterilize jar properly for longer shelf life.","Green chili paste is a versatile condiment kept in every Sri Lankan kitchen."))
R.append(m(314,"Mango Chutney","accompaniment","easy",10,20,4,"Island-wide",1,[("ripe mango","2"),("sugar","1/2 cup"),("vinegar","1/4 cup"),("ginger","1 inch"),("cinnamon","1/2 tsp"),("cloves","2"),("chili flakes","1 tsp"),("salt","to taste")],"1. Peel and dice mango\n2. Cook with sugar and vinegar on low heat\n3. Add grated ginger, spices\n4. Stir regularly for 15-20 mins\n5. Cook until thick and glossy\n6. Cool, store in sterilized jar","Use ripe but still firm mangoes for best chutney.","Mango chutney reflects colonial influence on Sri Lankan cuisine."))
R.append(m(315,"Gingelly Oil Sambol (Thala Thel Sambol)","accompaniment","easy",5,0,4,"Northern Province",3,[("sesame oil","2 tbsp"),("chili powder","2 tbsp"),("Maldive fish","1 tbsp"),("red onion","1"),("lime juice","1 tbsp"),("salt","to taste")],"1. Finely chop onion\n2. Mix chili powder with sesame oil\n3. Add Maldive fish and onion\n4. Add lime juice and salt\n5. Mix well\n6. Serve with string hoppers or pittu","Use dark roasted sesame oil for authentic flavor.","Sesame oil sambol is unique to Tamil cuisine in Northern Sri Lanka."))

# DESSERTS (25) SL_0316-0340
R.append(m(316,"Watalappan","dessert","medium",15,60,6,"Island-wide",0,[("coconut milk","2 cups"),("jaggery","200g"),("eggs","5"),("cardamom","1/2 tsp"),("nutmeg","1/4 tsp"),("cashew nuts","2 tbsp"),("cloves","4")],"1. Melt jaggery in warm coconut milk, strain\n2. Beat eggs well\n3. Mix jaggery-coconut milk with eggs\n4. Add cardamom, nutmeg, cloves\n5. Pour into mold, top with cashews\n6. Steam for 45-60 minutes until set","Do not overbeat eggs - we don't want air bubbles.","Watalappan is Sri Lanka's most beloved dessert, a Malay-origin coconut custard served at every celebration."))
R.append(m(317,"Kavum (Oil Cakes)","dessert","hard",30,45,12,"Island-wide",0,[("rice flour","2 cups"),("coconut milk","1/2 cup"),("treacle (kithul)","1 cup"),("salt","pinch"),("oil for frying","4 cups")],"1. Mix treacle with coconut milk\n2. Add rice flour gradually to make thick batter\n3. Rest batter 30 mins\n4. Heat oil to medium temperature\n5. Pour small amounts, fry on low heat\n6. Turn when bottom is golden, cook both sides until dark golden","Temperature control is critical - too hot and outside burns, too cool and they absorb oil.","Kavum is the iconic Sinhala and Tamil New Year sweet, symbolizing prosperity and goodness."))
R.append(m(318,"Kokis (Crispy Rosette Cookies)","dessert","hard",20,30,12,"Island-wide",0,[("rice flour","2 cups"),("coconut milk","1 cup"),("eggs","2"),("sugar","2 tbsp"),("salt","pinch"),("turmeric","1/4 tsp"),("oil for frying","4 cups")],"1. Mix rice flour, coconut milk, eggs, sugar, salt, turmeric\n2. Make smooth batter (like thick cream consistency)\n3. Heat oil, heat kokis mold in oil\n4. Dip hot mold into batter (3/4 only!)\n5. Immerse in hot oil, shake gently to release\n6. Fry until golden and crispy","Never dip the mold fully in batter or it won't release.","Kokis are intricate rosette-shaped cookies of Dutch-Malay origin, an essential New Year treat."))
R.append(m(319,"Aluwa (Flour Halwa)","dessert","medium",10,30,12,"Island-wide",0,[("rice flour","2 cups"),("treacle","1 cup"),("cashew nuts","1/4 cup"),("cardamom","1/2 tsp"),("ghee","2 tbsp")],"1. Dry roast rice flour until fragrant\n2. Heat treacle until it forms a soft ball in water\n3. Add roasted flour to treacle, stir vigorously\n4. Add ghee, cardamom, chopped cashews\n5. Pour into greased tray\n6. Cut into diamond shapes before fully cool","The treacle temperature test is crucial - too cool won't set, too hot burns.","Aluwa is a traditional sweet made for the Sinhala New Year, using kithul treacle."))
R.append(m(320,"Love Cake","dessert","medium",20,45,12,"Western Province",0,[("semolina","500g"),("butter","250g"),("sugar","500g"),("eggs","12"),("cashew nuts","250g"),("mixed peel","100g"),("honey","2 tbsp"),("rose water","1 tbsp"),("cardamom","1 tsp"),("nutmeg","1/2 tsp"),("cinnamon","1 tsp"),("lime zest","1 tbsp")],"1. Cream butter and sugar until light\n2. Add egg yolks one at a time\n3. Fold in semolina, chopped cashews, mixed peel\n4. Add honey, rose water, spices, lime zest\n5. Fold in whipped egg whites gently\n6. Bake at 150C for 40-45 mins until golden","Do not overbake - it should be moist and dense.","Love cake is Sri Lanka's most famous Dutch Burgher creation, traditionally made for Christmas and weddings."))
R.append(m(321,"Bibikkan (Coconut Cake)","dessert","medium",15,45,8,"Western Province",0,[("semolina","2 cups"),("grated coconut","2 cups"),("jaggery","1 cup"),("cashew nuts","1/2 cup"),("dates","1/2 cup"),("mixed spices","1 tsp"),("eggs","3"),("butter","2 tbsp")],"1. Mix semolina and grated coconut\n2. Melt jaggery, add to mixture\n3. Add beaten eggs, butter\n4. Fold in chopped cashews, dates, spices\n5. Pour into greased baking tin\n6. Bake at 170C for 40 minutes","The jaggery gives a deep caramel color and unique flavor.","Bibikkan is a Christmas specialty in Sri Lankan homes, combining local ingredients with European baking."))
R.append(m(322,"Kithul Treacle Curd","dessert","easy",5,0,4,"Sabaragamuwa",0,[("buffalo curd","500g"),("kithul treacle","1 cup")],"1. Set thick buffalo curd in clay pot\n2. Drizzle kithul treacle generously over curd\n3. Serve immediately\n4. Mix treacle and curd together when eating\n5. Enjoy the sweet-tangy combination\n6. May add chopped banana for extra sweetness","Use well-set, thick buffalo curd - not thin yogurt.","Curd and treacle is Sri Lanka's simplest and most beloved dessert, sold at roadside stalls across the country."))
R.append(m(323,"Puhul Dosi (Ash Pumpkin Preserve)","dessert","easy",15,60,8,"Island-wide",0,[("ash pumpkin","1 kg"),("sugar","750g"),("lime juice","2 tbsp"),("cardamom","3 pods"),("cloves","3"),("rose water","1 tsp")],"1. Peel pumpkin, cut into cubes, remove seeds\n2. Soak in lime water overnight to firm up\n3. Drain, add to pot with sugar\n4. Cook on low heat until translucent\n5. Add cardamom, cloves, rose water\n6. Cool - the syrup will thicken","Soaking in lime water keeps the pumpkin firm during cooking.","Puhul dosi is a translucent, jewel-like sweetmeat served at weddings and New Year."))
R.append(m(324,"Dodol","dessert","hard",15,180,12,"Western Province",0,[("coconut milk","6 cups"),("rice flour","2 cups"),("jaggery","500g"),("cashew nuts","1/2 cup"),("cardamom","1 tsp")],"1. Extract thick and thin coconut milk\n2. Cook thin coconut milk with jaggery until dissolved\n3. Add rice flour, stir continuously\n4. Cook on low heat for 2-3 hours, stirring constantly\n5. Add thick coconut milk, cashews, cardamom\n6. Pour into greased tray when mixture pulls away from pot","Continuous stirring for hours is essential - this is a labor of love.","Dodol is a traditional jelly-like sweet of Malay origin, requiring hours of stirring. Making dodol is often a communal family activity."))
R.append(m(325,"Aggala (Rice Ball Sweets)","dessert","easy",15,15,12,"Island-wide",0,[("rice flour","2 cups"),("grated coconut","1 cup"),("treacle","3/4 cup"),("cardamom","1/4 tsp"),("salt","pinch")],"1. Dry roast rice flour until fragrant\n2. Toast grated coconut separately\n3. Mix flour and coconut\n4. Warm treacle slightly\n5. Add treacle to flour mix, combine well\n6. Shape into small balls while still warm","Shape quickly while warm - the mixture hardens as it cools.","Aggala are simple rice and treacle balls traditionally made by grandmothers for children as a healthy snack."))
R.append(m(326,"Kalu Dodol (Dark Dodol)","dessert","hard",15,180,12,"Western Province",0,[("coconut milk","8 cups"),("rice flour","1 cup"),("jaggery","750g"),("cashew nuts","1/2 cup"),("cardamom","1 tsp"),("nutmeg","1/4 tsp")],"1. Extract coconut milk in stages\n2. Dissolve jaggery in thin coconut milk\n3. Add rice flour, stir continuously\n4. Cook 3+ hours on very low heat\n5. Add thick coconut milk gradually\n6. Pour into tray when very thick and dark","The darker it gets, the better the flavor.","Kalu dodol is the prestigious dark version of dodol, a must-have at Sinhala New Year."))
R.append(m(327,"Coconut Ice","dessert","easy",10,15,12,"Island-wide",0,[("desiccated coconut","2 cups"),("condensed milk","1 can"),("sugar","1 cup"),("food coloring","pink, few drops"),("vanilla","1 tsp")],"1. Mix coconut, condensed milk, sugar, vanilla\n2. Cook on low heat stirring constantly until thick\n3. Divide into two portions\n4. Add pink coloring to one half\n5. Press white layer into tray, then pink on top\n6. Cool and cut into squares","Press layers firmly for clean-cut squares.","Coconut ice is a beloved Sri Lankan sweet often sold at school fairs and charity events."))
R.append(m(328,"Milk Toffee","dessert","medium",5,30,12,"Island-wide",0,[("sugar","2 cups"),("milk","1 cup"),("butter","2 tbsp"),("vanilla","1 tsp"),("cashew nuts","1/4 cup")],"1. Combine sugar, milk, butter in heavy pot\n2. Cook on medium heat, stirring constantly\n3. When mixture reaches soft ball stage (115C)\n4. Remove from heat, add vanilla and cashews\n5. Beat vigorously until thick and creamy\n6. Pour into greased tray, cut while warm","Use a candy thermometer for perfect texture.","Milk toffee is Sri Lanka's most popular homemade sweet, made by every household for celebrations."))
R.append(m(329,"Sago Pudding","dessert","easy",10,25,4,"Island-wide",0,[("sago pearls","1 cup"),("coconut milk","2 cups"),("sugar","1/2 cup"),("cardamom","1/4 tsp"),("cashew nuts","2 tbsp"),("raisins","2 tbsp")],"1. Soak sago in water 30 mins, drain\n2. Cook sago in thin coconut milk until translucent\n3. Add sugar, cardamom\n4. Add thick coconut milk\n5. Pour into molds, top with cashews and raisins\n6. Chill until set","Soak sago well to reduce cooking time.","Sago pudding is a cooling dessert popular across Sri Lanka, especially during hot weather."))
R.append(m(330,"Tropical Fruit Salad","dessert","easy",15,0,4,"Island-wide",0,[("papaya","1 cup"),("pineapple","1 cup"),("mango","1 cup"),("banana","2"),("passion fruit","2"),("lime juice","2 tbsp"),("sugar","1 tbsp"),("ice cream","optional")],"1. Cut all fruits into bite-sized pieces\n2. Scoop passion fruit pulp\n3. Combine all fruits in bowl\n4. Sprinkle sugar and lime juice\n5. Toss gently\n6. Serve chilled, optionally with ice cream","Use ripe, seasonal tropical fruits for best flavor.","Sri Lanka's tropical fruit salad showcases the island's incredible diversity of fresh fruits."))
R.append(m(331,"Helapa","dessert","medium",20,20,10,"Southern Province",0,[("kurakkan flour","1 cup"),("grated coconut","1 cup"),("jaggery","1/2 cup"),("cardamom","1/4 tsp"),("kenda leaf","10")],"1. Mix flour, coconut, grated jaggery, cardamom\n2. Add water to make thick paste\n3. Place spoonfuls on kenda leaves\n4. Wrap into parcels\n5. Steam for 15-20 minutes\n6. Serve in the leaf wrapping","Use fresh kenda leaves for the aromatic wrapping.","Helapa is an ancient sweet wrapped in wild ginger leaves, giving it a unique aroma."))
R.append(m(332,"Falooda Pudding","dessert","easy",15,10,4,"Island-wide",0,[("falooda seeds","2 tbsp"),("milk","2 cups"),("sugar","3 tbsp"),("rose syrup","2 tbsp"),("ice cream","2 scoops"),("jelly","1/2 cup"),("falooda noodles","1/2 cup")],"1. Soak falooda seeds in water until expanded\n2. Cook falooda noodles, cool\n3. Cut jelly into cubes\n4. Layer in glass: noodles, seeds, jelly\n5. Pour sweetened rose milk over\n6. Top with ice cream","Layer in a tall glass for visual appeal.","Falooda is a beloved Sri Lankan dessert drink of Indian-Malay origin, sold at every sweet shop."))
R.append(m(333,"Mung Kavum (Green Gram Sweets)","dessert","medium",30,30,12,"Island-wide",0,[("green gram flour","2 cups"),("rice flour","1 cup"),("coconut milk","1 cup"),("treacle","1 cup"),("cardamom","1/4 tsp"),("oil for frying","3 cups")],"1. Mix both flours\n2. Add treacle and coconut milk to form thick batter\n3. Add cardamom\n4. Rest for 30 minutes\n5. Drop spoonfuls into medium-hot oil\n6. Fry slowly until dark golden brown","Low temperature frying is essential for cooked centers.","Mung kavum are the green gram variety of the Traditional New Year kavum."))
R.append(m(334,"Bolo Fiado (Layer Cake)","dessert","hard",30,60,12,"Western Province",0,[("butter","250g"),("sugar","250g"),("eggs","10"),("flour","250g"),("vanilla","1 tsp"),("nutmeg","1/4 tsp"),("cinnamon","1/4 tsp"),("brandy","2 tbsp")],"1. Cream butter and sugar until fluffy\n2. Add egg yolks one at a time\n3. Fold in flour and spices\n4. Add brandy and vanilla\n5. Whip egg whites, fold in gently\n6. Bake in layers under a grill, one layer at a time","Each layer must be individually grilled for the striped effect.","Bolo fiado is a Portuguese-origin layer cake unique to Sri Lankan Burgher Christmas celebrations."))
R.append(m(335,"Breudher (Christmas Bread)","dessert","hard",120,45,12,"Western Province",0,[("flour","4 cups"),("butter","250g"),("sugar","1/2 cup"),("eggs","4"),("yeast","2 tsp"),("milk","1 cup"),("mixed peel","1/2 cup"),("semolina","2 tbsp"),("nutmeg","1/2 tsp"),("cinnamon","1/2 tsp")],"1. Dissolve yeast in warm milk with sugar\n2. Mix flour, semolina, spices\n3. Add beaten eggs, melted butter\n4. Knead into soft dough, add mixed peel\n5. Prove 2 hours until doubled\n6. Shape, prove again, bake at 180C for 40 mins","Double proving is essential for light, fluffy bread.","Breudher is the Dutch-Burgher Christmas bread, a beloved holiday tradition unique to Sri Lanka."))
R.append(m(336,"Coconut Roti with Jaggery","dessert","easy",10,15,4,"Island-wide",0,[("rice flour","1 cup"),("grated coconut","1 cup"),("jaggery","1/2 cup scraped"),("salt","pinch")],"1. Mix flour, coconut, scraped jaggery, salt\n2. Add water sparingly to form stiff dough\n3. Shape into thick rounds\n4. Cook on griddle both sides until done\n5. The jaggery melts creating sweet spots\n6. Serve warm","Do not add too much water - dough should be very stiff.","A sweet variation of the classic pol roti, enjoyed as a snack or dessert."))
R.append(m(337,"Semolina Pudding","dessert","easy",5,20,4,"Island-wide",0,[("semolina","1 cup"),("milk","3 cups"),("sugar","1/2 cup"),("cardamom","1/4 tsp"),("cashews","2 tbsp"),("raisins","2 tbsp"),("butter","2 tbsp")],"1. Dry roast semolina in butter until golden\n2. Heat milk, add sugar\n3. Add roasted semolina slowly, stirring constantly\n4. Add cardamom, cashews, raisins\n5. Cook until thick, pour into mold\n6. Chill and serve","Roasting semolina first gives a nutty flavor.","Semolina pudding is a quick, easy dessert loved by children across Sri Lanka."))
R.append(m(338,"Date and Nut Cake","dessert","medium",20,45,10,"Western Province",0,[("dates","250g"),("butter","125g"),("sugar","1 cup"),("eggs","3"),("flour","2 cups"),("baking powder","1.5 tsp"),("cashews","1/2 cup"),("vanilla","1 tsp"),("cinnamon","1/2 tsp")],"1. Chop dates, soak in hot water 15 mins\n2. Cream butter and sugar\n3. Add eggs one at a time\n4. Fold in flour and baking powder\n5. Add dates, chopped cashews, vanilla, cinnamon\n6. Bake at 170C for 40-45 minutes","Use soft Medjool-style dates for moist cake.","Date and nut cake is popular during the Christmas season in Sri Lankan homes."))
R.append(m(339,"Pani Walalu (Treacle Jaggery Sweets)","dessert","hard",15,30,10,"Island-wide",0,[("urad dhal flour","1 cup"),("rice flour","1 cup"),("treacle","1 cup"),("water","as needed"),("oil for frying","3 cups")],"1. Soak urad dhal, grind to paste\n2. Mix with rice flour and water to make thick batter\n3. Fill batter into squeeze bottle or coconut shell with holes\n4. Pipe spirals into medium-hot oil\n5. Fry until golden\n6. Dip in warm treacle, drain","Pipe into oil in spiral shapes - practice makes perfect.","Pani walalu are golden spiral-shaped sweets dipped in kithul treacle, a quintessential New Year treat."))
R.append(m(340,"Caramel Pudding","dessert","medium",15,60,6,"Island-wide",0,[("sugar","1 cup"),("milk","2 cups"),("eggs","4"),("vanilla","1 tsp"),("water","2 tbsp")],"1. Caramelize half the sugar with water until dark amber\n2. Pour into mold, swirl to coat bottom\n3. Beat eggs with remaining sugar\n4. Heat milk (don't boil), add vanilla\n5. Mix egg mixture into milk, strain into mold\n6. Steam or bake in water bath 50-60 mins until set","Strain the custard for ultra-smooth texture.","Caramel pudding is the most popular dessert at Sri Lankan restaurants and parties."))

